var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"23:27 ARC-KP1\\n알파트릭스 본사 앞\\n<color=#ffd34c>사건 발생 약 30분 전</color>","JPN":"23:27 ARC-KP1\\nアルファトリックス本社前\\n<color=#ffd34c>事件発生約30分前</color>","ENG":"23:27 ARC-KP1\\nIn front of Alphatrix HQ\\n<color=#ffd34c>Approximately 30 minutes before Incident</color>","TWN":"23:27 ARC-KP1\\n阿爾法崔克斯總公司前\\n<color=#ffd34c>事件發生前約30分鐘</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이렇게 직접 얼굴 보는 건 오랜만이군, 이 실장.","JPN":"こうやって顔を合わせるのは久しぶりだな、シノザキ室長。","ENG":"It’s been a while since we last saw each other, hasn’t it, Chief?","TWN":"李室長，我們好久不見了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"여기서 오래 기다렸나?","JPN":"だいぶ待たせてしまったかな？","ENG":"Have you been waiting here for long?","TWN":"你在這裡等很久嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아닙니다. 부회장님.","JPN":"いいえ、副会長。","ENG":"Not at all, Vice Chairman.","TWN":"不會，副會長。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래. 차에 타게나. 집까지 데려다 주지.","JPN":"そうか、車に乗るといい。家まで送ろう。","ENG":"Good. Get in. I’ll take you home.","TWN":"上車吧，我載你回去。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"괜찮네. 내 운전수는 입이 무거우니까.","JPN":"大丈夫だ、私の運転手は口が堅いから。","ENG":"Don’t worry. My driver is not one to talk to others about this.","TWN":"放心吧，我的司機嘴巴很牢靠。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네라면 내 거취에 대한 이야기는 이미 들었겠지.","JPN":"君なら私の去就について、すでに聞いているだろうな。","ENG":"I’m sure you already heard what’s going to happen to me.","TWN":"你應該有聽說我的事吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……예. 이사진들이 그간 칼을 갈고 있었더군요.","JPN":"……はい、理事たちが用意周到に計画を練っていたそうですね。","ENG":"...Yes. I heard the board has been planning this for a long time now.","TWN":"……有，這段時間董事們一直在伺機而動。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래. 소식을 듣고 나도 이제 할 만큼 했나 싶더군.","JPN":"ああ。それを聞いて私もそろそろ潮時かと思ったよ。","ENG":"Yes. After hearing the news, I thought it was the end of the line for me.","TWN":"嗯嗯，我聽到消息後在想，我是否已經做完我該做的。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 늙은 너구리들에게 뒤통수를 맞는 날이 올 줄이야.","JPN":"あの老いぼれタヌキどもに裏切られる日が来るとは。","ENG":"Who knew those dusty baboons would stab me in the back like that.","TWN":"沒想到會被那些老狐狸給擺一道！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"하긴…… 권한대행이라는 핑계로 너무 오랫동안 회장 자리를 비워두긴 했어.","JPN":"まあ……権限代行に留まって、長らく会長職を空席のままにしていたからな。","ENG":"But then again, we did leave the seat vacant for far too long under the guise of having an acting Chairman.","TWN":"也是……畢竟假借代理職務的名義，會長的位置已經閒置許久。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아니, 사실은 그저 회장 자리에 앉기 두려웠던 거겠지.","JPN":"いや、本当は会長の座に就くのが怖かったのだろう。","ENG":"Truth be told, I was afraid of actually becoming <color=#ffd34c>President</color>.","TWN":"不，其實是我害怕坐上會長的位置。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아버지는 집안에선 망할 쓰레기였지만 회사에선 사업의 신이나 마찬가지였으니까.","JPN":"父は家庭では救いようのないクズ野郎だったが、\\n会社では仕事の神のような存在だったからな。","ENG":"Even though Father was regarded as trash by his family, he was regarded as a god at work.","TWN":"雖然爸在家裡是無可救藥的垃圾，但他在公司裡的地位跟神一樣。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"회장 자리에 앉아서 그 양반보다 못하다고 비교당하는 건……. 상상만으로도 끔찍해.","JPN":"会長になって、父と比べて無能だと言われるのは……\\n想像するだけでゾッとする。","ENG":"Being President and constantly being compared to him... Even imagining it is terrifying.","TWN":"我怕我當上會長後，大家覺得我做得比他差勁……光想就覺得可怕。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네 머리 굴리는 소리가 여기까지 들리는군.","JPN":"君が言葉を探して頭を回しているのがひしひしと伝わるな。","ENG":"I can see you’re trying to figure out why I wanted to see you.","TWN":"你心裡是這麼想的吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"너무 긴장하지 말게. 아부나 듣자고 보려던 게 아냐.","JPN":"あまり緊張しないでくれ。\\nお世辞を言ってもらうために呼び出したわけではないんだ。","ENG":"Don’t be so nervous. I didn’t ask to see you so you could kiss up to me.","TWN":"不用緊張，我找你不是想聽什麼奉承的話。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네 생각은 어떻지? 이사회가 누굴 밀어 줄 것 같나?","JPN":"君の考えはどうだ？　理事会は誰を推すと思う？","ENG":"I just wanted to know what you thought. Who do you think the board is going to back?","TWN":"我是想問問你的想法？你覺得董事會會推選誰？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……어디까지나 제 좁은 식견이지만.","JPN":"……あくまで私の一方的な意見にすぎませんが、","ENG":"...With all due respect...","TWN":"……這只是我個人的淺見，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이사회는 신씨 집안과 관계없이 그룹의 장기 침체를 타파할 수 있는 인물에 주목할 겁니다.","JPN":"理事会はヒメノ家とは関係が無く、\\nグループの長期低迷を打破できる人物に注目すると思います。","ENG":"Regardless of any connections any candidate has with the Shin family, the board will choose someone who can lead the Group out of its long slump.","TWN":"董事會應該會推選跟沈家沒關係，而且能夠打破集團長期窘境的人。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"넉넉잡아 두셋 정도를 꼽을 수 있겠죠.","JPN":"多めに見積もっても2人、3人くらいに絞られるでしょう。","ENG":"I believe there are two to three potential candidates.","TWN":"符合條件的人應該有2、3位。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그야 그렇겠지. 그것들은 우리 집안에 형님 말고는 인물이 없다고 떠들어댔으니 말이야.","JPN":"まあ、そうだろうな。我が一族には兄以外に人材がいないと騒いでいたからな。","ENG":"Ah, yes. They were always saying how my big brother was best fit to run the company.","TWN":"我想也是，那些傢伙認為我們沈家除了大哥之外，都沒有其他人才。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"예를 들면?","JPN":"例えば、どのあたりだ？","ENG":"Any names?","TWN":"那你說說看有誰？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"우선, <color=#ffd34c>일렉트로닉스</color> 대표가 유력하겠죠. 전자제품 분야는 실적 부진을 극복한 이력이 있으니 말입니다.","JPN":"まず、<color=#ffd34c>エレクトロニクス</color>の代表が有力でしょう。\\n電子製品分野は業績不振を打開した実績がありますので。","ENG":"To begin with, the CEO of <color=#ffd34c>Electronics</color> is one. Because that person has a track record of overcoming sluggish performance in our electronics sector.","TWN":"首先最有力的人選應該是<color=#ffd34c>電子</color>的代表。畢竟他有過讓電子產品業績起死回生的經驗。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"괜찮은 친구긴 한데 사람이 너무 경박해. 계열사 수장 정도가 적당하지.","JPN":"悪くはないが、薄っぺらい人物だ。系列会社の社長くらいがピッタリだろう。","ENG":"I guess so. But that fellow’s too carefree. More suited as a head of one of the divisions, in my opinion.","TWN":"他是還不錯，但太個性輕浮，充其量只能當個分公司的總經理吧！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"사교성은 부족하지만 <color=#ffd34c>메카닉스</color> 대표는 어떻겠나?","JPN":"社交性は足りないが、<color=#ffd34c>メカニックス</color>の代表はどうだ？","ENG":"Although he lacks some social skills, what about the CEO of <color=#ffd34c>Mechanics</color>?","TWN":"那你覺得<color=#ffd34c>機械</color>的代表怎麼樣？雖然他不太善常社交。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그분이 지금처럼 사분오열된 그룹을 조율할 수 있을 거라는 기대는 안 드는군요.","JPN":"あの方が今の分裂したグループをうまくまとめられるとは思えませんね。","ENG":"I do not expect him to be able to lead the Group in its divided state right now.","TWN":"我不認為他有能力，可以將四分五裂的集團重新整合起來。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"해외에 계신 부회장님 동생 분은 어떠십니까?","JPN":"海外にいらっしゃる、副会長のご令妹様はいかがですか？","ENG":"How about your sibling overseas?","TWN":"副會長在國外的妹妹怎麼樣？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"최근 <color=#ffd34c>바이오닉스</color>도 안정세를 되찾았더군요.","JPN":"最近<color=#ffd34c>バイオニクス</color>も安定を取り戻したようですし。","ENG":"I heard <color=#ffd34c>Bionics</color> has recently regained stability.","TWN":"最近<color=#ffd34c>仿生</color>好像也開始恢復穩定。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……자네가 사람을 액면 그대로 볼 때가 다 있군.","JPN":"……君も表面だけで判断する時があるんだな。","ENG":"...I had no idea you saw people for what they were worth at face value.","TWN":"……想不到你也有誤判的時候。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 녀석은 싹수부터 글렀어. 회사야 어디서 그럴싸한 컨설턴트라도 건져 왔겠지.","JPN":"あいつは根っからのダメ人間だ。業績が回復したのは、腕利きのコンサルタントでもスカウトしたからだろう。","ENG":"No, she’s ill-fit. The company must have found a good consultant somewhere.","TWN":"她就是個沒出息的傢伙。很明顯是不知道從哪找來一個顧問吧！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……죄송합니다. 심기를 불편하시게 만들 생각은 없었습니다. ","JPN":"……申し訳ありません。ご気分を害するつもりはございませんでした。","ENG":"...My apologies. I didn’t mean to offend you.","TWN":"……抱歉，我不是故意要惹副會長心煩。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 괴물은 어떨 것 같나?","JPN":"あの化け物はどうだろうか？","ENG":"How about that monster?","TWN":"你覺得那怪物呢？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 아가씨는 아직 너무 어립니다. 회장 자리를 맡기에는 경험도 부족하죠.","JPN":"ユイお嬢様はまだ若すぎます。\\n会長を務めるには経験も足りません。","ENG":"Jia is still too young. She is also too inexperienced to be taken seriously if she becomes President.","TWN":"沈佳小姐還小，以小姐的經驗還不足以坐上會長的位置。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 괴물에게 경험이 필요하다고? 이 실장도 농담이 많이 늘었군.","JPN":"あの化け物に経験が必要だって？　なかなか面白い冗談じゃないか。","ENG":"That monster needs experience? My, your sense of humor has gotten better.","TWN":"那個怪物還需要經驗？李室長真會開玩笑呢！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저는 부회장님 지시대로 줄곧 아가씨를 감시해 왔습니다.","JPN":"私は副会長の指示どおり、ずっとお嬢様を監視してきました。","ENG":"I have been observing Miss Jia as you ordered.","TWN":"我一直按著副會長的指示，在小姐身邊監視著。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨에게 무언가 기묘한 재능이 있다는 건 인정하겠습니다만……. 그저 그뿐입니다.","JPN":"お嬢様に何か不思議な才能があることは認めますが……ただ、それだけです。","ENG":"I will admit that she has an uncanny ability... But that’s all there is to it.","TWN":"我承認小姐是有特殊的能力沒錯……但就僅此而已。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 외에는 부모 말 잘 듣는 아이일 뿐이죠. 공략할 수 있는 부분은 다른 또래들보다 더 많은 편입니다.","JPN":"それ以外は、親の言うことをよく聞く子どもでしかありません。\\nむしろ、付け込める要素は同年代の子どもたちよりも多いほうです。","ENG":"Other than that, she’s just a girl who listens to her parents. However, she does seem to be more vulnerable than her peers.","TWN":"除此之外，小姐不過就只是個聽話的孩子。 她比其他同年紀的孩子都還沒有心機。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"흐음……. 뭔가 잊은 것 같군, 이 실장.","JPN":"ふむ……何か忘れていないか、シノザキ室長。","ENG":"Hmm... I think you’re forgetting something, Chief Lee.","TWN":"嗯……李室長，你是不是忘了？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"나는 기회가 생겼을 때 그 괴물을 없애라고 자네를 이노베이션에 심어 둔 걸세.","JPN":"私はあの化け物を消す機会を窺うために、\\n君をイノベーションに潜入させたつもりだ。","ENG":"I put you in Innovation so that you can get rid of her when the opportunity arises.","TWN":"當初我派你去改革時，是要你一有機會就把那個怪物除掉。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내가 언제 자네에게 베이비시터 노릇까지 하라고 했던가?","JPN":"君に子守りの役まで頼んだおぼえは無いが？","ENG":"Did I put you on babysitting duties?","TWN":"我是叫你去當保母的嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"잊지 않았습니다. 부회장님은 분명 괴물을 없애라고 하셨죠.","JPN":"忘れていません。副会長は確かに化け物を消せと命じられました。","ENG":"I haven’t forgotten. You specifically ordered me to get rid of that monster.","TWN":"我沒忘，副會長確實是要我把怪物除掉。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……집안 싸움에 휘말린 여자아이가 아니라요.","JPN":"……それは、一族の争いに巻き込まれた少女ではないはずです。","ENG":"...And that she’s not a girl stuck between a family feud.","TWN":"……但不是要我把捲入家族紛爭的孩子除掉。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"줄곧 말씀드리려고 했습니다만, 경황이 없어 이제야 말씀드리게 되는군요.","JPN":"ずっと申し上げようと思っていたのですが、それどころではなかったため遅くなりました。","ENG":"I've been meaning to tell you this for a long time, and I haven’t had the opportunity to tell you this until now.","TWN":"我之前就一直想跟副會長說，只是一直找不到機會，那就藉這個機會報告副會長，"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"전 여기까지만 하겠습니다, 부회장님.","JPN":"私はここで身を引こうと思います、副会長。","ENG":"I quit, Vice Chairman.","TWN":"我不會再幫您監視小姐。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부회장님 지시에 따랐던 건 그룹을 위해서였지, 가련한 여자애를 죄인으로 매달려던 게 아니었으니까요.","JPN":"副会長の指示に従ったのはグループのためであり、\\n可憐な少女を犠牲にするためではありません。","ENG":"I followed your orders for the betterment of the Group, not to make an innocent girl a sinner.","TWN":"我之所以會聽副會長的指示，是為了集團好，而不是為了要替一個可憐的孩子冠上罪名。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래……. 그만두겠단 말이지…….","JPN":"そうか……辞めるというのか……","ENG":"I see... So you want to quit...","TWN":"嗯……你不幹了是吧……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"정에 휘둘리지 않는 냉혈한이라고 생각했는데, 자네도 많이 변했군.","JPN":"感情に振り回されることのない冷酷な人間だと思っていたが、\\n君もずいぶん変わったようだな。","ENG":"I always considered you to be ruthless, but you’ve changed.","TWN":"我原本以為你很冷血，不會受感情左右，看來你也變了不少。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"면목없습니다. 하지만 저는…….","JPN":"申し訳ございません。ですが、私は……","ENG":"I’m sorry, but I...","TWN":"很抱歉，不過我……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"변명할 것 없네. 대신 내가 하나만 묻지.","JPN":"言い訳はいいんだ。その代わり、一つだけ聞かせてくれ。","ENG":"No need for excuses. But let me ask you this.","TWN":"不需要解釋，我只問你一句。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 결정이 정말 자네 머릿속에서 나온 거라고 확신할 수 있나?","JPN":"その決断が、本当に自分で考えたことだと言い切れるか？","ENG":"Are you sure that conclusion was made by you?","TWN":"你確定這個決定真的是從你腦袋裡冒出來的嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"Pardon?","TWN":"……什麼意思？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네가 무슨 근거로 그 괴물을 가련하다고 지껄이는지 모르겠지만…….","JPN":"君が何を根拠にあの化け物のことを可憐だなんて言うのかはわからないが……","ENG":"I don’t know what makes you think that monster is innocent, but...","TWN":"我是不清楚你判斷那個怪物可憐的依據是什麼……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 발상 자체가 괴물에게 놀아난 결과란 의심은 해 본 적 없나?","JPN":"その発想自体が、あの化け物に翻弄された結果だと疑ったことはないか？","ENG":"Have you thought of the possibility that you got played by her?","TWN":"難道你沒想過，這個想法很可能是那個怪物加給你的嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그게 대체…… 무슨 말씀이십니까?","JPN":"それはいったい……どういうことでしょうか？","ENG":"W-what do you mean?","TWN":"我不太明白……您的意思？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"실장, 나는 자네보다 더 오랫동안 그 괴물을 지켜봐 왔어.","JPN":"室長、私は君よりも長い間あの化け物を見守ってきた。","ENG":"I’ve known that monster longer than you have, Ms. Lee.","TWN":"李室長，我認識那個怪物的時間比你還久。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"형님이 세상을 떠난 뒤로 내가 쓸 수 있는 수단은 모두 써서, 그 괴물에 대해 조사했지.","JPN":"兄が亡くなった後、あらゆる手段であの化け物について調べた。","ENG":"When my brother died, I did everything in my power to research about that thing.","TWN":"自從大哥過世後，我便用盡一切方法來調查那個怪物。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그리고 마침내 그 괴물을 이 세상에서 매장해 버릴 수 있는 실마리를 손에 넣은 걸세.","JPN":"そして、ついにあの化け物を葬る手掛かりを手に入れたのだ。","ENG":"Now, I finally found a way to turn the world against that monster.","TWN":"最後終於得到可以將那個怪物，埋葬在這個世界裡的線索。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하지만 부회장님, 그런 게 있다면 어째서…….","JPN":"ですが副会長。そのようなものがあるなら、どうして……","ENG":"But sir... If you had known about something that...","TWN":"若是如此，那您為何……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"공개하지 않았냐고? 그럴 수가 없었으니까.","JPN":"公開していないのかって？　そんなことはできなかったからだ。","ENG":"Why did I stay quiet about it? Because I had no choice.","TWN":"為何不公開嗎？當然是因為不能公開。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 괴물에 대해 밝혀졌다간 알파트릭스 그룹에 치명적인…….","JPN":"あの化け物のことが世に知られたら、アルファトリックスグループに致命的な……","ENG":"If word gets out about that monster, Alphatrix Group will never recover...","TWN":"公開的話，會對阿爾法崔克斯集團產生致命性的……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이런 제기랄! 갑자기 왜 멈춘 거야! 운전 똑바로 안 해!","JPN":"おい！　なぜ急停止するんだ！　ちゃんと運転せんか！","ENG":"Damn it! Driver! Why’d you stop?!","TWN":"搞什麼！為什麼緊急剎車！你會不會開車！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"죄, 죄송합니다! 앞차가 갑자기 멈추는 바람에……!","JPN":"す、すみません！　前の車が急に止まったもので……！","ENG":"A-apologies, sir! The car in front suddenly stopped and...!","TWN":"對…對不起，因為前面的車突然停住……！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이 새끼가 비싼 돈 처먹고 변명은!","JPN":"この野郎、高い給料を払ってやってるのに言い訳しやがって！","ENG":"I don’t pay you to make excuses!","TWN":"是想製造假車禍是吧！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"앞차에 탄 놈들 다 내리게 해! 저런 것들은 감옥에 처넣어야 정신을 차리지!","JPN":"前の車に乗っている奴らを全員降ろせ！\\nあんなやつら、全員刑務所にぶち込んでやる！","ENG":"Remove those bozos in front! Those idiots need to rot in jail to learn their lesson!","TWN":"叫前面那輛車裡的人下來！我要把他們全送去吃牢飯，看他們會不會清醒一點！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"알겠습니다! 잠시만 기다려 주십시오!","JPN":"承知しました！　少々お待ちください！","ENG":"Yes sir! I’ll get right on it!","TWN":"是，副會長，請稍等！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"……어, 어어? 저 트럭 뭐야? 왜 속도를 안 줄여?","JPN":"……え、ええっ？　あのトラックは何だ？　なぜ減速しない？","ENG":"H-huh...? Why’s that truck... not slowing down?","TWN":"……欸欸欸？那台卡車怎麼回事？怎麼還不減速？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부회장님! 엎드리세요!","JPN":"副会長！　伏せてください！","ENG":"Vice Chairman! Watch out!","TWN":"副會長！趴下！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SHIP"},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……님!","JPN":"……長！","ENG":"—man!","TWN":"副……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부회장님! 정신이 드시나요?","JPN":"副会長！　気が付きましたか？","ENG":"Vice Chairman! Are you all right?!","TWN":"副會長！您醒醒！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"큭……. 자네가…… 도와 준 건가?","JPN":"くっ……君が……助けてくれたのか？","ENG":"Kugh.... You... saved my life...","TWN":"唔……是你……救了我嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부상이 심하십니다. 말씀을 아끼세요. 바로 병원으로 모셔다 드리겠습니다.","JPN":"重傷です、安静にしてください。すぐに病院へ搬送します｡","ENG":"You’re badly wounded. Stop talking. I’ll get you to the hospital quickly.","TWN":"您傷得很重，先不要說話，我立刻送您去醫院。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……이렇게 넓은 도로에서 부회장님이 탄 차에 정확하게 들이받았어.","JPN":"……こんなに広い道路で、副会長の車に正確に突っ込んできた。","ENG":"Whoever it was, they crashed right into Vice Chairman’s car on purpose.","TWN":"……路上車這麼多，竟然可以精準地撞上副會長的座車。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이건 절대 사고가 아니야. 명백하게 의도한 거지.","JPN":"これは絶対事故なんかじゃない。明らかに狙って行われた。","ENG":"This wasn’t an accident. Someone set this up.","TWN":"這絕對不是個普通的意外，很明顯是刻意的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하지만 지금 같은 시기에 부회장님을 노린다고? 대체 누가? 뭘 위해서?","JPN":"でも、どうしてこんな時期に副会長を？　いったい誰が？　何のために？","ENG":"But why go after him now? Who would do that? To what end?","TWN":"不過現在怎麼有人會想要對副會長不利？到底是誰？目的又是什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어…….","JPN":"ど……","ENG":"Uh...","TWN":"怎……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어째서……?","JPN":"どうして……","ENG":"But why...?","TWN":"怎麼會……？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어째서 당신이 여기에……?","JPN":"どうしてあなたがここに……？","ENG":"W-why are you here...?","TWN":"為什麼你會……？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"23:59:56","JPN":"23:59:56","ENG":"23:59:56","TWN":"23:59:56"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"23:59:57","JPN":"23:59:57","ENG":"23:59:57","TWN":"23:59:57"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"23:59:58","JPN":"23:59:58","ENG":"23:59:58","TWN":"23:59:58"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"23:59:59","JPN":"23:59:59","ENG":"23:59:59","TWN":"23:59:59"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CLOCK_03"},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"00:00 ARC-KP1\\n센트럴 브릿지 부근\\n<color=#ff3636>사건 발생</color>","JPN":"00:00 ARC-KP1\\nセントラルブリッジ付近\\n<color=#ff3636>事件発生</color>","ENG":"00:00 ARC-KP1\\nNear Central Bridge\\n<color=#ff3636>Time of Incident</color>","TWN":"00:00 ARC-KP1\\n中央大橋附近\\n<color=#ff3636>事件發生</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"}]`);export{e as default};